import React from 'react';
import 'bootstrap/dist/css/bootstrap.min.css';  // Подключение стилей Bootstrap
import EventList from './EventList';  // Импорт компонента с мероприятиями

function App() {
  return (
    <div className="App">
      {/* Навигационная панель */}
      <nav className="navbar navbar-expand-lg navbar-dark bg-primary">
        <a className="navbar-brand" href="#">Организация Мероприятий</a>
        <button className="navbar-toggler" type="button" data-bs-toggle="collapse" data-bs-target="#navbarNav" aria-controls="navbarNav" aria-expanded="false" aria-label="Toggle navigation">
          <span className="navbar-toggler-icon"></span>
        </button>
        <div className="collapse navbar-collapse" id="navbarNav">
          <ul className="navbar-nav">
            <li className="nav-item active">
              <a className="nav-link" href="#">Главная</a>
            </li>
            <li className="nav-item">
              <a className="nav-link" href="#">Мероприятия</a>
            </li>
          </ul>
        </div>
      </nav>

      {/* Список мероприятий */}
      <EventList />
    </div>
  );
}

export default App;
